// // Combines two 10-bit input signals, I1 and I2, to produce a 10-bit output S. The output is generated by performing a bitwise OR operation between I1 and a mask of alternating bits (1010101010) while also performing a bitwise OR operation between I2 and a complementary mask (0101010101), followed by a bitwise AND of the results.
module top_module(
    input [9:0] I1,
    input [9:0] I2,
    output reg [9:0] S
);// Calculate the output using the given equation
always @*
    S = (I1 & 10'b1010101010) | (I2 & 10'b0101010101);

endmodule
